import{_ as i,c as t,o as a,a2 as o}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/usage.md","filePath":"guide/usage.md","lastUpdated":1776396452000}'),r={name:"guide/usage.md"};function n(l,e,s,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="usage-guide" tabindex="-1">Usage Guide <a class="header-anchor" href="#usage-guide" aria-label="Permalink to &quot;Usage Guide&quot;">​</a></h1><h2 id="basic-navigation" tabindex="-1">Basic Navigation <a class="header-anchor" href="#basic-navigation" aria-label="Permalink to &quot;Basic Navigation&quot;">​</a></h2><h3 id="opening-images" tabindex="-1">Opening Images <a class="header-anchor" href="#opening-images" aria-label="Permalink to &quot;Opening Images&quot;">​</a></h3><ul><li><strong>File Menu</strong>: Click File &gt; Open to select individual images</li><li><strong>Folder View</strong>: Click File &gt; Open Folder to browse an entire directory</li><li><strong>Drag &amp; Drop</strong>: Drag image files or folders directly onto the application window</li><li><strong>Chrome Extension</strong>: Click the extension icon on any website to view all images</li></ul><h2 id="finder-sync-extension" tabindex="-1">Finder Sync Extension <a class="header-anchor" href="#finder-sync-extension" aria-label="Permalink to &quot;Finder Sync Extension&quot;">​</a></h2><h3 id="quick-image-processing-from-finder" tabindex="-1">Quick Image Processing from Finder <a class="header-anchor" href="#quick-image-processing-from-finder" aria-label="Permalink to &quot;Quick Image Processing from Finder&quot;">​</a></h3><p>The Finder Sync Extension adds a Nicasa button to your Finder toolbar for quick image processing:</p><ol><li>Select one or more images in Finder</li><li>Click the Nicasa toolbar button</li><li>Choose <strong>Image Optimizer</strong> to compress files or <strong>AI Image Editor</strong> to enhance images</li><li>Nicasa will open automatically and process the selected files</li></ol><h3 id="supported-formats" tabindex="-1">Supported Formats <a class="header-anchor" href="#supported-formats" aria-label="Permalink to &quot;Supported Formats&quot;">​</a></h3><p>The extension works with: JPG, PNG, GIF, BMP, WebP, SVG, TIFF, and ICO files.</p><h3 id="thumbnail-view" tabindex="-1">Thumbnail View <a class="header-anchor" href="#thumbnail-view" aria-label="Permalink to &quot;Thumbnail View&quot;">​</a></h3><p>The main interface shows thumbnails of your images:</p><ul><li><strong>Click</strong>: Select an image</li><li><strong>Double-click</strong>: Open in full view</li><li><strong>Right-click</strong>: Access context menu with options</li></ul><h3 id="full-view-mode" tabindex="-1">Full View Mode <a class="header-anchor" href="#full-view-mode" aria-label="Permalink to &quot;Full View Mode&quot;">​</a></h3><p>When viewing an image in full screen:</p><ul><li><strong>Zoom</strong>: Use mouse wheel or zoom controls</li><li><strong>Pan</strong>: Click and drag to move around zoomed images</li><li><strong>Navigation</strong>: Use arrow keys or on-screen buttons to go to next/previous image</li></ul><h2 id="screenshot-feature" tabindex="-1">Screenshot Feature <a class="header-anchor" href="#screenshot-feature" aria-label="Permalink to &quot;Screenshot Feature&quot;">​</a></h2><h3 id="taking-screenshots" tabindex="-1">Taking Screenshots <a class="header-anchor" href="#taking-screenshots" aria-label="Permalink to &quot;Taking Screenshots&quot;">​</a></h3><ol><li>Click the screenshot button in the toolbar or use keyboard shortcut</li><li>Select the area you want to capture</li><li>The screenshot will automatically open in Nicasa for editing</li></ol><h3 id="screen-recording-permission" tabindex="-1">Screen Recording Permission <a class="header-anchor" href="#screen-recording-permission" aria-label="Permalink to &quot;Screen Recording Permission&quot;">​</a></h3><p>For screenshot functionality, Nicasa needs screen recording permission:</p><ol><li>Go to System Settings &gt; Privacy &amp; Security &gt; Screen Recording</li><li>Check the box next to Nicasa</li><li>Restart Nicasa if necessary</li></ol><h2 id="ai-image-editor" tabindex="-1">AI Image Editor <a class="header-anchor" href="#ai-image-editor" aria-label="Permalink to &quot;AI Image Editor&quot;">​</a></h2><h3 id="ai-editor-overview" tabindex="-1">AI Editor Overview <a class="header-anchor" href="#ai-editor-overview" aria-label="Permalink to &quot;AI Editor Overview&quot;">​</a></h3><p>Nicasa includes powerful AI tools for image enhancement:</p><ul><li><strong>Auto Enhance</strong>: Automatically improve image quality</li><li><strong>Smart Crop</strong>: Intelligent cropping suggestions</li><li><strong>Color Correction</strong>: AI-powered color adjustments</li><li><strong>Noise Reduction</strong>: Remove noise and grain</li><li><strong>Sharpening</strong>: Intelligent sharpening without artifacts</li></ul><h3 id="inpainting-tool" tabindex="-1">Inpainting Tool <a class="header-anchor" href="#inpainting-tool" aria-label="Permalink to &quot;Inpainting Tool&quot;">​</a></h3><p>The inpainting tool allows you to:</p><ul><li>Remove unwanted objects from images</li><li>Fill in missing parts intelligently</li><li>Restore damaged areas</li><li>Clean up backgrounds</li></ul><h2 id="transparent-overlay-mode" tabindex="-1">Transparent Overlay Mode <a class="header-anchor" href="#transparent-overlay-mode" aria-label="Permalink to &quot;Transparent Overlay Mode&quot;">​</a></h2><p>Perfect for designers and artists:</p><ol><li>Open an image in Nicasa</li><li>Enable overlay mode from the View menu</li><li>Adjust transparency with the slider</li><li>The image will stay on top of all other windows</li><li>Use for tracing, reference work, or UI comparison</li></ol><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>Cmd+O</code></td><td>Open file</td></tr><tr><td><code>Cmd+Shift+O</code></td><td>Open folder</td></tr><tr><td><code>Space</code></td><td>Next image</td></tr><tr><td><code>Shift+Space</code></td><td>Previous image</td></tr><tr><td><code>Cmd+F</code></td><td>Toggle fullscreen</td></tr><tr><td><code>Cmd+W</code></td><td>Close window</td></tr><tr><td><code>Cmd+Q</code></td><td>Quit application</td></tr><tr><td><code>Delete</code></td><td>Delete current image</td></tr><tr><td><code>Cmd+S</code></td><td>Take screenshot</td></tr><tr><td><code>Cmd+E</code></td><td>Open AI editor</td></tr><tr><td><code>Cmd+T</code></td><td>Toggle overlay mode</td></tr></tbody></table><h2 id="chrome-extension-integration" tabindex="-1">Chrome Extension Integration <a class="header-anchor" href="#chrome-extension-integration" aria-label="Permalink to &quot;Chrome Extension Integration&quot;">​</a></h2><h3 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h3><ol><li>Install the <a href="https://chromewebstore.google.com/detail/nicasa-Image-viewer/cihceekeiedkinpjjjfehlgjdhpeokbj" target="_blank" rel="noreferrer">Nicasa Chrome Extension</a></li><li>The extension icon will appear in your browser toolbar</li></ol><h3 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h3><ol><li>Visit any website</li><li>Click the Nicasa extension icon</li><li>View all images from the page in a grid</li><li>Click any image to open it in Nicasa</li><li>Use all Nicasa features on web images</li></ol><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Access settings through Nicasa &gt; Preferences:</p><ul><li><strong>General</strong>: Default folder, language, theme</li><li><strong>Viewing</strong>: Thumbnail size, zoom behavior, animations</li><li><strong>Editor</strong>: AI tool preferences, default enhancements</li><li><strong>Extensions</strong>: Chrome extension settings</li><li><strong>Privacy</strong>: Data collection preferences</li></ul><h2 id="supported-formats-1" tabindex="-1">Supported Formats <a class="header-anchor" href="#supported-formats-1" aria-label="Permalink to &quot;Supported Formats&quot;">​</a></h2><p>Nicasa supports all common image formats:</p><ul><li><p><strong>Standard</strong>: JPEG, PNG, GIF, BMP, TIFF, WebP</p></li><li><p><strong>RAW</strong>: CR2, NEF, ARW, DNG (with conversion)</p></li><li><p><strong>Vector</strong>: SVG (with rasterization)</p></li><li><p><strong>Animated</strong>: GIF, APNG</p></li><li><p>JPEG/JPG</p></li><li><p>PNG</p></li><li><p>GIF (static)</p></li><li><p>BMP</p></li><li><p>TIFF</p></li><li><p>WebP</p></li><li><p>HEIC (on supported systems)</p></li></ul><h2 id="tips-and-tricks" tabindex="-1">Tips and Tricks <a class="header-anchor" href="#tips-and-tricks" aria-label="Permalink to &quot;Tips and Tricks&quot;">​</a></h2><ul><li>Use the search bar to quickly find images by filename</li><li>Create collections by organizing images in folders</li><li>Use the rating system to mark your favorite images</li><li>Export images in different formats through the File menu</li></ul>',47)])])}const m=i(r,[["render",n]]);export{u as __pageData,m as default};
